import React from 'react';
import { BrowserRouter, Routes, Route } from 'react-router-dom';
import Navbar from './components/Navbar';
import Home from './pages/Home';
import Doctors from './pages/Doctors';
import BookAppointment from './pages/BookAppointment';
import Appointments from './pages/Appointments';

export default function App() {
  return (
    <BrowserRouter>
      <Navbar />
      <Routes>
        <Route path='/' element={<Home />} />
        <Route path='/doctors' element={<Doctors />} />
        <Route path='/book' element={<BookAppointment />} />
        <Route path='/appointments' element={<Appointments />} />
      </Routes>
    </BrowserRouter>
  );
}

import React from 'react';
import { NavLink } from 'react-router-dom';

export default function Navbar() {
  const style = ({ isActive }) => ({ textDecoration: 'none', color: isActive ? '#0f172a' : '#64748b', fontWeight: isActive ? 700 : 500 });

  return (
    <nav style={{ borderBottom: '1px solid #e2e8f0', background: '#fff' }}>
      <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '16px 24px', display: 'flex', justifyContent: 'space-between' }}>
        <h2 style={{ margin: 0 }}>ClinicCare</h2>
        <div style={{ display: 'flex', gap: '18px' }}>
          <NavLink to='/' style={style}>Home</NavLink>
          <NavLink to='/doctors' style={style}>Doctors</NavLink>
          <NavLink to='/book' style={style}>Book</NavLink>
          <NavLink to='/appointments' style={style}>Appointments</NavLink>
        </div>
      </div>
    </nav>
  );
}

import React from 'react';

export default function DoctorCard({ doctor }) {
  return (
    <div style={{ border: '1px solid #e2e8f0', borderRadius: '14px', padding: '16px', background: '#fff' }}>
      <h3 style={{ marginTop: 0 }}>{doctor.name}</h3>
      <p style={{ color: '#64748b' }}>{doctor.specialization}</p>
      <p><strong>Fee:</strong> ${doctor.fee}</p>
      <button style={{ marginTop: '8px', padding: '10px 14px', borderRadius: '10px', border: 'none', background: '#0f172a', color: '#fff' }}>
        Book Slot
      </button>
    </div>
  );
}

import React from 'react';

export default function Home() {
  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <div style={{ background: '#f8fafc', borderRadius: '18px', padding: '32px', border: '1px solid #e2e8f0' }}>
        <h1>Book your clinic appointment with ease</h1>
        <p style={{ color: '#64748b', maxWidth: '700px' }}>
          Browse doctors, select available slots, and keep track of your bookings in one clean portal.
        </p>
      </div>
    </div>
  );
}

import React from 'react';
import DoctorCard from '../components/DoctorCard';

const doctors = [
  { id: 1, name: 'Dr. Sara Khan', specialization: 'Dermatology', fee: 30 },
  { id: 2, name: 'Dr. Ali Raza', specialization: 'Cardiology', fee: 45 },
  { id: 3, name: 'Dr. Hina Shah', specialization: 'General Medicine', fee: 25 }
];

export default function Doctors() {
  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <h1>Doctors</h1>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '18px' }}>
        {doctors.map(doctor => <DoctorCard key={doctor.id} doctor={doctor} />)}
      </div>
    </div>
  );
}

import React from 'react';

export default function BookAppointment() {
  return (
    <div style={{ maxWidth: '800px', margin: '0 auto', padding: '32px 24px' }}>
      <h1>Book Appointment</h1>
      <div style={{ border: '1px solid #e2e8f0', borderRadius: '14px', padding: '20px', background: '#fff' }}>
        <div style={{ display: 'grid', gap: '14px' }}>
          <input placeholder='Patient Name' style={{ padding: '12px', borderRadius: '10px', border: '1px solid #cbd5e1' }} />
          <select style={{ padding: '12px', borderRadius: '10px', border: '1px solid #cbd5e1' }}>
            <option>Select Doctor</option>
            <option>Dr. Sara Khan</option>
            <option>Dr. Ali Raza</option>
          </select>
          <input type='date' style={{ padding: '12px', borderRadius: '10px', border: '1px solid #cbd5e1' }} />
          <button style={{ padding: '12px', borderRadius: '10px', border: 'none', background: '#0f172a', color: '#fff' }}>Confirm Booking</button>
        </div>
      </div>
    </div>
  );
}

import React from 'react';

const appointments = [
  { id: 301, doctor: 'Dr. Sara Khan', date: '2026-03-28', status: 'Confirmed' },
  { id: 302, doctor: 'Dr. Hina Shah', date: '2026-04-02', status: 'Pending' }
];

export default function Appointments() {
  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <h1>Appointments</h1>
      <table style={{ width: '100%', borderCollapse: 'collapse', border: '1px solid #e2e8f0' }}>
        <thead style={{ background: '#f8fafc' }}>
          <tr>
            <th style={{ padding: '12px', textAlign: 'left' }}>Doctor</th>
            <th style={{ padding: '12px', textAlign: 'left' }}>Date</th>
            <th style={{ padding: '12px', textAlign: 'left' }}>Status</th>
          </tr>
        </thead>
        <tbody>
          {appointments.map(item => (
            <tr key={item.id}>
              <td style={{ padding: '12px', borderTop: '1px solid #e2e8f0' }}>{item.doctor}</td>
              <td style={{ padding: '12px', borderTop: '1px solid #e2e8f0' }}>{item.date}</td>
              <td style={{ padding: '12px', borderTop: '1px solid #e2e8f0' }}>{item.status}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

from flask import Flask, jsonify

app = Flask(__name__)

@app.route('/api/doctors')
def get_doctors():
    return jsonify({
        'doctors': [
            {'id': 1, 'name': 'Dr. Sara Khan', 'specialization': 'Dermatology', 'fee': 30},
            {'id': 2, 'name': 'Dr. Ali Raza', 'specialization': 'Cardiology', 'fee': 45},
            {'id': 3, 'name': 'Dr. Hina Shah', 'specialization': 'General Medicine', 'fee': 25}
        ]
    })

@app.route('/api/appointments')
def get_appointments():
    return jsonify({
        'appointments': [
            {'id': 301, 'doctor_name': 'Dr. Sara Khan', 'appointment_date': '2026-03-28', 'status': 'Confirmed'},
            {'id': 302, 'doctor_name': 'Dr. Hina Shah', 'appointment_date': '2026-04-02', 'status': 'Pending'}
        ]
    })

if __name__ == '__main__':
    app.run(debug=True)
